import { ICustomField } from '@domain/customField';
import { useEffect, useState } from 'react';
import { FieldError, useFormContext, useWatch } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { CheckboxControl } from '../CheckboxControl';
import { FormCheckboxGroup } from '../CheckboxGroup/FormCheckboxGroup';
import { FormDateTimeControl } from '../DateTimeControl';
import { FormInputControl } from '../FormInputControl';
import { FormRadioGroup, RadioControl } from '../RadioButtonGroup';
import { FormSelectControl } from '../SelectControl';
import { FormTextAreaControl } from '../TextAreaControl';
import { RequirementCustomField } from './RequirementCustomField';

interface IProps {
  customField: ICustomField;
  isReadOnly?: boolean;
  isRequired?: boolean;
  name: string;
}

export const CustomField = ({ customField, isReadOnly, isRequired, name }: IProps) => {
  const { clearErrors, formState, register, setError, setValue } = useFormContext();
  const { t } = useTranslation(['common', 'actionPagesBuilder']);
  const customFieldValue = useWatch({ name });
  const [isTouched, setIsTouched] = useState<boolean | null>(null);
  const customFieldId = name?.split('.')?.[1] as keyof FieldError;
  const hasError = !!formState?.errors?.customFieldResponsesAttributes?.[customFieldId];
  const { hasFloatLabel, helpText, inputType, label } = customField ?? {};

  const options =
    customField?.inputType === 'question'
      ? [
          { label: t('common:yes'), value: 'yes' },
          { label: t('common:no'), value: 'no' },
        ]
      : (customField?.options?.values ?? []).map((option) => ({
          label: option.text,
          value: option.text ?? option.id,
        }));

  const variant = hasFloatLabel ? 'floating' : 'outline';

  useEffect(() => {
    if (!customFieldValue && customField) {
      if (inputType === 'checkbox') {
        const defaultValues = customField.options?.values
          ?.filter((x) => x.default)
          .map((x) => x.text ?? x.id);

        setValue(name, defaultValues);
      } else {
        const defaultValue = customField.options?.values?.find((x) => x.default);
        if (defaultValue) {
          setValue(name, defaultValue.text ?? defaultValue.id ?? '');
        }
      }
    }
  }, [customField, customFieldValue, setValue, name, inputType]);

  useEffect(() => {
    // Clear error from required field after value is selected or entered
    if (isRequired) {
      if (!!customFieldValue || customFieldValue === true) {
        clearErrors(name);
      }
    }
  }, [clearErrors, customFieldValue, isRequired, name]);

  // biome-ignore lint/correctness/useExhaustiveDependencies: intentional extra dependencies
  useEffect(() => {
    // Clear error from required checkbox field after value is selected
    if (isRequired && inputType === 'checkbox' && hasError && customFieldValue?.length > 0) {
      clearErrors(name);
      setIsTouched(true);
    }
  }, [clearErrors, customFieldId, customFieldValue, hasError, inputType, isRequired, name]);

  // biome-ignore lint/correctness/useExhaustiveDependencies: intentional extra dependencies
  useEffect(() => {
    // Set error on required checkbox field if value is unselected
    if (
      isRequired &&
      // Don't set error on mount
      isTouched &&
      inputType === 'checkbox' &&
      !hasError &&
      customFieldValue?.length === 0
    ) {
      setError(name, {
        message: 'This field is required',
        type: 'manual',
      });
    }
  }, [customFieldId, customFieldValue, hasError, inputType, isRequired, isTouched, name, setError]);

  switch (inputType) {
    case 'birthday':
    case 'date':
      return (
        // Prevent gapping issues with the date picker's hidden element
        <div>
          <FormDateTimeControl
            className="mt-4"
            formHelperText={helpText}
            isRequired={isRequired}
            label={label}
            readOnly={isReadOnly}
            type="fullDate"
            variant={variant}
            {...register(name)}
          />
        </div>
      );
    case 'checkbox':
      return (
        <FormCheckboxGroup
          formControlProps={{ isRequired }}
          formHelperText={helpText ?? undefined}
          label={label ?? undefined}
          {...register(name)}
        >
          <div className="flex flex-col gap-2">
            {options.map((option, idx) => (
              <CheckboxControl
                inputClassName={hasError ? 'border-red-500 border' : ''}
                isReadOnly={isReadOnly}
                key={`${option.value}-${idx + 1}`}
                value={option.value}
              >
                {option.label}
              </CheckboxControl>
            ))}
          </div>
        </FormCheckboxGroup>
      );
    case 'text':
      return (
        <FormInputControl
          formHelperText={helpText}
          isReadOnly={isReadOnly}
          isRequired={isRequired}
          label={label}
          variant={variant}
          {...register(name)}
        />
      );
    case 'hidden':
      return <input type="hidden" {...register(name)} />;
    case 'text_area':
      return (
        <FormTextAreaControl
          formHelperText={helpText}
          isReadOnly={isReadOnly}
          isRequired={isRequired}
          label={label}
          variant={variant}
          {...register(name)}
        />
      );
    case 'radio':
    case 'question':
      return (
        <FormRadioGroup
          formControlProps={{ className: 'mb-2' }}
          formHelperText={helpText}
          isRequired={isRequired}
          label={label}
          {...register(name)}
        >
          <div
            className="flex flex-col gap-2"
            style={{
              flexDirection: customField?.inputType === 'question' ? 'row' : 'column',
            }}
          >
            {options.map((option, idx) => (
              <RadioControl
                checkboxClassName={hasError ? 'border-red-500 !border' : ''}
                isReadOnly={isReadOnly}
                key={`${option.value}-${idx + 1}`}
                value={option.value}
              >
                {option.label}
              </RadioControl>
            ))}
          </div>
        </FormRadioGroup>
      );
    case 'select':
      return (
        <FormSelectControl
          className={hasError ? 'border-2 border-red-500' : ''}
          formHelperText={helpText}
          isReadOnly={isReadOnly}
          isRequired={isRequired}
          label={label}
          options={options}
          placeholder="-"
          // Use the outline variant for Selection Lists. The floating variant is best
          // for single-line labels and users might enter very long label text.

